SELECT AVG(planning_time) AS average_planning_time
FROM planning_problems
WHERE solver = 'solver1';

SELECT solver_name 
FROM solvers 
WHERE solver_id = 1;

SELECT problem_id
FROM planning_problems
WHERE problem_type = 'islands-0';

SELECT AVG(planning_time) AS average_planning_time
FROM planning_problems
WHERE solver = 'solver1' AND difficulty_level IN ('medium', 'hard');

SELECT problem_file 
FROM planning_problems 
WHERE problem_id = 0;

SELECT AVG(planning_time) AS AveragePlanningTime
FROM planning_problems
WHERE solver = 'X';

SELECT description
FROM planning_problems
WHERE problem_type = 'islands-1';

SELECT problem_id 
FROM planning_problems 
WHERE solver = 'FF';

SELECT problem_id, problem_type
FROM planning_problems
WHERE difficulty_level = 'hard';
